// RED PHASE - Write failing test
@Test
public void testValidPassword() {
 LoginValidator validator = new LoginValidator();
 assertFalse(validator.validate("abc")); // Password too short
}

// GREEN PHASE - Minimal code to pass
class LoginValidator {
 public boolean validate(String password) {
 return password.length() >= 6;
 }
}

// REFACTOR PHASE - Improve code
class LoginValidator {
 private static final int MIN_LENGTH = 6;

 public boolean validate(String password) {
 if (password == null) return false;
 return password.length() >= MIN_LENGTH;
 }
}

// User Story Format
// "As a [role], I want [feature] so that [benefit]"

// Example:
// Story ID: US-001
// Title: User Password Reset
// 
// As a registered user,
// I want to reset my password via email,
// so that I can regain access to my account if I forget my password.

// Acceptance Criteria:
// 1. User receives email within 5 minutes
// 2. Reset link expires after 24 hours
// 3. User can set new password

// Story Points: 5
// Priority: High

// XP Team Sprint Structure
TEAM_SIZE = 4
PAIRS = TEAM_SIZE / 2
SPRINT_LENGTH = 2 weeks

PROCEDURE DailyRotation(pairs[]):
 FOR each day in sprint:
 // Pairs work together on stories
 FOR each pair in pairs:
 driver = pair[0]
 navigator = pair[1]

 // Rotate roles every 2 hours
 SWAP_ROLES(pair)

 // At end of day, consider pair rotation
 IF day % 2 == 0:
 pairs = ROTATE_PAIRS(pairs)

// Benefits:
// - Knowledge sharing
// - Reduced bottlenecks 
// - Multiple perspectives
// - Consistent code ownership
